<script setup lang="ts">
import { CalendarHeart, Camera, Check, Copy, Heart, Link2, LoaderCircle, LogOut, ShieldCheck, Unlink, X } from '@lucide/vue'
const emit = defineEmits<{ close: []; logout: []; unlinked: []; relationshipUpdated: [] }>()
const { profile } = useCoupleAuth()
const { relationshipStart, loadAnniversaries } = useAnniversaries()
const { members, accountLoading, loadMembers, updateName, updateRelationshipStart, uploadAvatar, regenerateInvitation, unlinkCouple } = useAccountManagement()
const name = ref(profile.value?.displayName || '')
const startDate = ref(relationshipStart.value)
const busy = ref(false); const code = ref(''); const copied = ref(false); const error = ref(''); const success = ref(''); const confirmUnlink = ref(false)
onMounted(async () => { await Promise.all([loadMembers(), loadAnniversaries()]); startDate.value = relationshipStart.value })
async function run(action: () => Promise<void>) { busy.value = true; error.value = ''; success.value = ''; try { await action() } catch (e: any) { error.value = e.message } finally { busy.value = false } }
async function saveName() { if (name.value.trim()) await run(() => updateName(name.value.trim())) }
async function saveStart() { await run(async () => { await updateRelationshipStart(startDate.value); await loadAnniversaries(); startDate.value = relationshipStart.value; success.value = '在一起的日期已更新'; emit('relationshipUpdated') }) }
async function chooseAvatar(event: Event) { const file = (event.target as HTMLInputElement).files?.[0]; if (!file) return; if (file.size > 5 * 1024 * 1024) { error.value = '头像不能超过 5 MB'; return } await run(async () => { await uploadAvatar(file) }) }
async function makeCode() { await run(async () => { code.value = await regenerateInvitation() }) }
async function copy() { await navigator.clipboard.writeText(code.value); copied.value = true; setTimeout(() => copied.value = false, 1200) }
async function unlink() { await run(async () => { await unlinkCouple(); emit('unlinked') }) }
</script>

<template>
  <div class="account-overlay" @click.self="emit('close')"><section class="account-panel">
    <header><div><p class="eyebrow">OUR ACCOUNT</p><h2>双人账户</h2></div><button type="button" aria-label="关闭" @click="emit('close')"><X :size="20" /></button></header>
    <div v-if="accountLoading" class="loading"><LoaderCircle class="spin" :size="22" /> 正在读取成员</div>
    <div v-else class="members"><article v-for="member in members" :key="member.id"><div class="member-avatar"><img v-if="member.avatarUrl" :src="member.avatarUrl" alt="成员头像"><span v-else>{{ member.displayName.slice(0, 1) }}</span><label v-if="member.id === profile?.id" title="更换头像"><Camera :size="14" /><input type="file" accept="image/jpeg,image/png,image/webp" hidden @change="chooseAvatar"></label></div><div><strong>{{ member.displayName }}</strong><small>{{ member.id === profile?.id ? '这是你' : '你的伴侣' }}</small></div><ShieldCheck v-if="member.id === profile?.id" :size="17" /></article></div>
    <section class="setting-section"><h3>我的称呼</h3><div class="name-row"><input v-model="name" maxlength="40"><button type="button" :disabled="busy" @click="saveName"><Check :size="16" />保存</button></div></section>
    <section class="setting-section"><h3>在一起的日期</h3><p>修改后，双方首页和纪念日的实时计时会同步更新。</p><div class="date-row"><CalendarHeart :size="19" /><input v-model="startDate" type="date" :max="new Date().toISOString().slice(0, 10)"><button type="button" :disabled="busy" @click="saveStart"><Check :size="16" />更新</button></div></section>
    <section class="setting-section"><h3>邀请伴侣</h3><p>邀请码有效期为 7 天。重新生成不会影响已经绑定的成员。</p><button v-if="!code" class="outline-action" type="button" :disabled="busy" @click="makeCode"><Link2 :size="17" />生成新邀请码</button><button v-else class="invite-code" type="button" @click="copy"><strong>{{ code }}</strong><Copy :size="17" /><span>{{ copied ? '已复制' : '复制' }}</span></button></section>
    <p v-if="success" class="panel-success">{{ success }}</p><p v-if="error" class="panel-error">{{ error }}</p>
    <footer><button type="button" @click="emit('logout')"><LogOut :size="17" />退出登录</button><button class="unlink" type="button" @click="confirmUnlink = true"><Unlink :size="17" />解除关系</button></footer>
    <div v-if="confirmUnlink" class="confirm-box"><Heart :size="25" /><h3>确定离开情侣空间？</h3><p>共同数据会保留，但你将失去访问权限。此操作不会删除对方账户。</p><div><button type="button" @click="confirmUnlink = false">取消</button><button class="danger" type="button" :disabled="busy" @click="unlink">确认解除</button></div></div>
  </section></div>
</template>

<style scoped>
.account-overlay{position:fixed;z-index:60;inset:0;display:grid;place-items:center;padding:20px;background:rgba(45,39,52,.28);backdrop-filter:blur(10px)}.account-panel{position:relative;width:min(100%,540px);max-height:calc(100vh - 40px);overflow:auto;padding:27px;border:1px solid rgba(255,255,255,.9);border-radius:34px;background:linear-gradient(145deg,#fffaff,#fff3f9);box-shadow:0 30px 80px rgba(50,39,61,.18)}.account-panel>header{display:flex;justify-content:space-between}.account-panel h2{margin:0;color:#4d2c57;font-size:28px}.account-panel>header button{display:grid;place-items:center;width:37px;height:37px;border:0;border-radius:12px;background:#f0ebf5}.members{display:grid;grid-template-columns:1fr 1fr;gap:9px;margin-top:22px}.members article{display:flex;align-items:center;gap:10px;padding:13px;border:1px solid rgba(181,112,207,.2);border-radius:24px;background:rgba(255,255,255,.82)}.member-avatar{position:relative;width:45px;height:45px;flex:0 0 45px}.member-avatar img,.member-avatar>span{display:grid;place-items:center;width:100%;height:100%;border-radius:50%;object-fit:cover;background:linear-gradient(135deg,#b7a1da,#dfa2b8);color:#fff;font-weight:750}.member-avatar label{position:absolute;right:-3px;bottom:-2px;display:grid;place-items:center;width:22px;height:22px;border:2px solid white;border-radius:8px;background:#332f3a;color:#fff;cursor:pointer}.members article>div:nth-child(2){min-width:0;flex:1}.members strong,.members small{display:block}.members strong{font-size:12px;overflow-wrap:anywhere}.members small{margin-top:3px;color:#98909f;font-size:8px}.members article>svg{color:#70a083}.setting-section{margin-top:22px;padding-top:19px;border-top:1px solid rgba(181,112,207,.15)}.setting-section h3{margin:0 0 9px;font-size:13px}.setting-section p{margin:-3px 0 12px;color:#918999;font-size:10px;line-height:1.6}.name-row,.date-row{display:flex;align-items:center;gap:8px}.date-row{padding-left:13px;border:1px solid #e4d9e8;border-radius:20px;background:#fff;color:#9863ac}.name-row input,.date-row input{min-width:0;flex:1;padding:12px;border:1px solid #e4dee7;border-radius:20px;outline:0;background:#fff;font:inherit}.date-row input{border:0}.name-row button,.date-row button,.outline-action{display:flex;align-items:center;gap:6px;align-self:stretch;padding:0 15px;border:0;border-radius:20px;background:linear-gradient(135deg,#8b4db9,#d85f99);color:#fff;font-size:10px;font-weight:700}.date-row button{margin:4px;min-height:38px}.outline-action{min-height:42px;border:1px solid #e4dee7;background:#fff;color:#765ca6}.invite-code{display:flex;align-items:center;width:100%;min-height:50px;padding:0 14px;border:1px dashed #bca9d5;border-radius:21px;background:#f5f0fa;color:#735899}.invite-code strong{font-size:17px}.invite-code svg{margin-left:auto}.invite-code span{margin-left:6px;font-size:9px}.account-panel>footer{display:flex;gap:8px;margin-top:23px}.account-panel>footer button{display:flex;align-items:center;justify-content:center;gap:7px;min-height:42px;flex:1;border:1px solid #e6e0e9;border-radius:20px;background:#fff;font-size:10px}.unlink{color:#b75875}.panel-error,.panel-success{padding:10px 12px;border-radius:13px;font-size:10px}.panel-error{background:#ffe7ef;color:#bd5776}.panel-success{background:#e8f8ef;color:#4c8b68}.loading{display:flex;justify-content:center;gap:8px;padding:45px;color:#918999;font-size:10px}.confirm-box{position:absolute;z-index:2;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:40px;background:rgba(253,252,254,.97);text-align:center}.confirm-box>svg{color:#d68fa9}.confirm-box h3{margin:13px 0 7px}.confirm-box p{max-width:330px;margin:0;color:#887f8e;font-size:10px}.confirm-box>div{display:flex;gap:8px;margin-top:20px}.confirm-box button{padding:11px 17px;border:0;border-radius:12px}.confirm-box .danger{background:#b85c78;color:#fff}.spin{animation:spin 1s linear infinite}@keyframes spin{to{transform:rotate(360deg)}}@media(max-width:600px){.account-overlay{align-items:end;padding:0}.account-panel{max-height:92vh;padding:22px 18px calc(22px + env(safe-area-inset-bottom));border-radius:25px 25px 0 0}.members{grid-template-columns:1fr}.date-row{display:grid;grid-template-columns:auto 1fr}.date-row button{grid-column:1/-1;justify-content:center;margin:0 4px 4px}}
</style>
<style scoped>
@media(max-width:650px){.account-overlay{padding-top:env(safe-area-inset-top)}.account-panel{max-height:calc(100dvh - env(safe-area-inset-top));padding-top:19px}.account-panel h2{font-size:23px}.setting-section h3{font-size:12px}}
</style>
